+    pub const Complexity = enum(u8) {
+        constant,
+        linear,
+        quadratic,
+        exponential,
+        unknown,
+    };
+
+    pub fn init(
+        name: []const u8,
+        pattern: []const u8,
+        category: PatternCategory,
+        complexity: Complexity,
+    ) Self {
+        return .{
+            .name = name,
+            .pattern = pattern,
+            .category = category,
+            .expected_complexity = complexity,
+            .test_inputs = &[_]TestInput{},
