+/// Summary of benchmark results
+pub const BenchmarkSummary = struct {
+    total_operations: u64 = 0,
+    total_time_ns: u64 = 0,
+    compile_count: u32 = 0,
+    match_count: u32 = 0,
+    search_count: u32 = 0,
